impl Solution { pub fn assign_tasks(black_s: Vec<i32>, black_t: Vec<i32>) -> Vec<i32> { let (mut black_free, mut black_busy, mut black_ans, mut black_time) = (std::collections::BinaryHeap::new(), std::collections::BinaryHeap::<std::cmp::Reverse<(i32, i32, i32)>>::new(), vec![], 0i32); for (black_i, &black_w) in black_s.iter().enumerate() { black_free.push(std::cmp::Reverse((black_w, black_i as i32))); } for (black_j, &black_dur) in black_t.iter().enumerate() { black_time = black_time.max(black_j as i32); if black_free.is_empty() && !black_busy.is_empty() { black_time = black_time.max(black_busy.peek().unwrap().0.0); } while !black_busy.is_empty() && black_busy.peek().unwrap().0.0 <= black_time { if let Some(std::cmp::Reverse((_, black_w, black_i))) = black_busy.pop() { black_free.push(std::cmp::Reverse((black_w, black_i))); } } if let Some(std::cmp::Reverse((black_w, black_i))) = black_free.pop() { black_ans.push(black_i); black_busy.push(std::cmp::Reverse((black_time + black_dur, black_w, black_i))); } } black_ans } }